diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..623cbf25b1df 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4133,19 +4133,88 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
                        m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
                                        m_APInt(C2))))) &&
       (WO->getBinaryOp() == Instruction::Add ||
-       WO->getBinaryOp() == Instruction::Sub) &&
+       WO->getBinaryOp() == Instruction::Sub ||
+       WO->getBinaryOp() == Instruction::Mul) &&
       (ICmpInst::isEquality(Pred) ||
-       WO->isSigned() == ICmpInst::isSigned(Pred)) &&
-      match(WO->getRHS(), m_APInt(C1))) {
-    bool Overflow;
-    APInt NewC = WO->getBinaryOp() == Instruction::Add
-                     ? (ICmpInst::isSigned(Pred) ? C2->ssub_ov(*C1, Overflow)
-                                                 : C2->usub_ov(*C1, Overflow))
-                     : (ICmpInst::isSigned(Pred) ? C2->sadd_ov(*C1, Overflow)
-                                                 : C2->uadd_ov(*C1, Overflow));
-    if (!Overflow || ICmpInst::isEquality(Pred)) {
-      Value *NewCmp = Builder.CreateICmp(
-          Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
+       WO->isSigned() == ICmpInst::isSigned(Pred))) {
+    // For add/sub, the constant must be on the RHS (as per original pattern).
+    // For mul, we can handle constant on either side.
+    if (WO->getBinaryOp() == Instruction::Add ||
+        WO->getBinaryOp() == Instruction::Sub) {
+      if (!match(WO->getRHS(), m_APInt(C1)))
+        return nullptr;
+      bool Overflow;
+      APInt NewC = WO->getBinaryOp() == Instruction::Add
+                       ? (ICmpInst::isSigned(Pred) ? C2->ssub_ov(*C1, Overflow)
+                                                   : C2->usub_ov(*C1, Overflow))
+                       : (ICmpInst::isSigned(Pred) ? C2->sadd_ov(*C1, Overflow)
+                                                   : C2->uadd_ov(*C1, Overflow));
+      if (!Overflow || ICmpInst::isEquality(Pred)) {
+        Value *NewCmp = Builder.CreateICmp(
+            Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
+        return BinaryOperator::CreateOr(Ov, NewCmp);
+      }
+    } else {
+      // Multiplication.
+      const APInt *ConstC;
+      Value *X;
+      if (match(WO->getRHS(), m_APInt(ConstC))) {
+        X = WO->getLHS();
+      } else if (match(WO->getLHS(), m_APInt(ConstC))) {
+        X = WO->getRHS();
+      } else {
+        return nullptr;
+      }
+
+      if (ConstC->isZero()) {
+        // Multiplication by zero: product is always zero, overflow never occurs.
+        // The condition "overflow || (0 > C2)" simplifies to "0 > C2".
+        // This is already covered by other folds, but we can still handle.
+        // For simplicity, bail out.
+        return nullptr;
+      }
+      // Currently only support unsigned multiplication with inequality predicates.
+      if (WO->isSigned())
+        return nullptr; // TODO: support signed multiplication.
+
+      APInt NewC;
+      if (Pred == ICmpInst::ICMP_UGT) {
+        // X * C > C2  <=>  X > C2 / C (floor division)
+        NewC = C2->udiv(*ConstC);
+      } else if (Pred == ICmpInst::ICMP_UGE) {
+        // X * C >= C2 <=> X >= (C2 + C - 1) / C (ceil division)
+        // Compute ceil division: (C2 + *ConstC - 1).udiv(*ConstC)
+        APInt Dividend = *C2 + *ConstC - 1;
+        NewC = Dividend.udiv(*ConstC);
+      } else if (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_ULE) {
+        // TODO: adjust predicate appropriately.
+        return nullptr;
+      } else {
+        // Equality predicates could be handled if division is exact.
+        // For now, bail out.
+        return nullptr;
+      }
+      // Check if overflow flag being true implies the new compare is true.
+      // Overflow occurs when X > UINT_MAX / C.
+      unsigned BitWidth = X->getType()->getScalarSizeInBits();
+      APInt MaxX = APInt::getMaxValue(BitWidth).udiv(*ConstC);
+      APInt MinOverflowX = MaxX + 1;
+      // For UGT/UGE, overflow implies NewCmp true, so we can drop Ov.
+      bool OverflowImpliesNewCmp = false;
+      if (Pred == ICmpInst::ICMP_UGT)
+        OverflowImpliesNewCmp = MinOverflowX.ugt(NewC);
+      else if (Pred == ICmpInst::ICMP_UGE)
+        OverflowImpliesNewCmp = MinOverflowX.uge(NewC);
+      // If overflow never occurs (C == 1), we can drop Ov as it's always false.
+      if (MaxX.isMaxValue())
+        OverflowImpliesNewCmp = true;
+      if (OverflowImpliesNewCmp) {
+        // Overflow flag being true guarantees NewCmp true, so OR with Ov is equivalent to NewCmp.
+        // Create a new ICmp instruction without inserting it; the caller will insert.
+        return ICmpInst::Create(Instruction::ICmp, Pred, X,
+                                ConstantInt::get(X->getType(), NewC));
+      }
+      Value *NewCmp = Builder.CreateICmp(Pred, X, ConstantInt::get(X->getType(), NewC));
       return BinaryOperator::CreateOr(Ov, NewCmp);
     }
   }

